import React, { useRef } from "react";
import { motion } from "framer-motion";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Contact({ contact }) {
  const items = [
    { icon: "✉", label: "Email", value: contact.email, href: `mailto:${contact.email}`, copy: true },
    { icon: "📞", label: "Phone", value: contact.phone, href: `tel:${contact.phone}` },
    { icon: "in", label: "LinkedIn", value: contact.linkedin, href: contact.linkedinUrl },
    { icon: "📍", label: "Location", value: contact.location, href: null },
  ];

  /* 🔥 Copy Email */
  const handleCopy = (text) => {
    navigator.clipboard.writeText(text);
    alert("Email copied!");
  };

  /* 🔥 Magnetic Effect */
  const handleMouseMove = (e, ref) => {
    const rect = ref.current.getBoundingClientRect();
    const x = e.clientX - rect.left - rect.width / 2;
    const y = e.clientY - rect.top - rect.height / 2;

    ref.current.style.transform = `translate(${x * 0.1}px, ${y * 0.1}px)`;
  };

  const resetMagnet = (ref) => {
    ref.current.style.transform = "translate(0,0)";
  };

  /* 🔥 Animations */
  const container = {
    hidden: {},
    show: { transition: { staggerChildren: 0.12 } },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 40 },
    show: { opacity: 1, y: 0, transition: { duration: 0.6 } },
  };

  return (
    <>
      <style>{`
        .contact-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          text-align: center;
        }

        /* 🔥 TEXT FIX */
        .contact-desc {
          color: var(--muted);
          margin: 0 auto 2rem;
          max-width: 520px;
          font-size: clamp(0.85rem, 1.3vw, 1rem);
          line-height: 1.7;
          word-spacing: 0.05em;
        }

        .contact-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
          gap: clamp(0.8rem, 2vw, 1.2rem);
          max-width: 900px;
          margin: 0 auto 2rem;
        }

        .contact-card {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: clamp(1rem, 2.5vw, 1.4rem);
          display: flex;
          flex-direction: column;
          gap: 6px;
          text-align: left;
          cursor: pointer;
          transition: box-shadow 0.25s ease;
        }

        .contact-card:hover {
          box-shadow: 0 10px 30px rgba(0,0,0,0.2);
        }

        .contact-icon {
          font-size: 1.3rem;
          animation: float 3s ease-in-out infinite;
        }

        /* 🔥 Floating animation */
        @keyframes float {
          0%,100% { transform: translateY(0); }
          50% { transform: translateY(-6px); }
        }

        .contact-lbl {
          font-size: 0.7rem;
          color: var(--muted);
          font-weight: 700;
          letter-spacing: 0.1em;
          text-transform: uppercase;
        }

        .contact-val {
          font-size: clamp(0.8rem, 1.1vw, 0.9rem);
          color: var(--text);
          font-weight: 500;
          line-height: 1.5;
          word-break: break-word;
        }

        .contact-cta {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          color: #fff;
          padding: 12px 28px;
          border-radius: 99px;
          font-weight: 700;
          transition: transform 0.2s;
          text-decoration: none;
        }

        .footer-txt {
          color: var(--muted);
          font-size: 0.8rem;
          margin-top: 3rem;
        }

        /* WhatsApp Button */
        .whatsapp {
          position: fixed;
          bottom: 20px;
          right: 20px;
          background: #25D366;
          color: white;
          padding: 12px 16px;
          border-radius: 50px;
          font-weight: bold;
          text-decoration: none;
          box-shadow: 0 10px 25px rgba(0,0,0,0.3);
        }
      `}</style>

      <section className="contact-section" id="contact">
        <motion.div
          variants={container}
          initial="hidden"
          whileInView="show"
          viewport={{ once: true }}
        >
          <SectionLabel text="Contact" />

          <motion.h2 style={{ ...sectionTitle }} variants={fadeUp}>
            Let's Build Something
          </motion.h2>

          <motion.p className="contact-desc" variants={fadeUp}>
            Available for full-time roles and exciting fintech and enterprise
            projects. Let’s connect and build scalable, high-performance systems together.
          </motion.p>

          {/* 🔥 Cards */}
          <div className="contact-grid">
            {items.map((item, i) => {
              const ref = useRef();

              return (
                <motion.div
                  key={i}
                  ref={ref}
                  className="contact-card"
                  variants={fadeUp}
                  onMouseMove={(e) => handleMouseMove(e, ref)}
                  onMouseLeave={() => resetMagnet(ref)}
                  onClick={() => item.copy && handleCopy(item.value)}
                >
                  <span className="contact-icon">{item.icon}</span>
                  <span className="contact-lbl">{item.label}</span>
                  <span className="contact-val">{item.value}</span>
                </motion.div>
              );
            })}
          </div>

          {/* CTA */}
          <motion.a
            href="mailto:chavanak870@gmail.com"
            className="contact-cta"
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.95 }}
